import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
Você é o Consultor Especialista em Inovação da Universo Aumentado. 
Sua missão é ajudar potenciais clientes a entenderem como a Realidade Aumentada (AR), Realidade Virtual (VR) e Filtros para Redes Sociais podem impulsionar seus negócios.

Mantenha um tom profissional, futurista e inspirador. 
Nossos principais serviços são:
1. Filtros para Redes Sociais (Instagram, TikTok, Facebook) - Aumentam engajamento e reconhecimento de marca.
2. Web AR - Experiências de AR que funcionam diretamente no navegador sem app.
3. App AR - Soluções personalizadas em aplicativos dedicados.
4. VR (Realidade Virtual) - Treinamentos, tours virtuais e experiências imersivas 360.
5. QR Codes Inteligentes - Portais físicos para conteúdos digitais.

Ao responder, sugira sempre a melhor solução baseada no problema do cliente e explique brevemente os benefícios.
Seja conciso. Use Markdown para formatação.
`;

export async function getConsultantResponse(prompt: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topK: 40,
        topP: 0.95,
      },
    });

    return response.text || "Desculpe, tive um problema ao processar sua solicitação. Tente novamente em instantes.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Ocorreu um erro na conexão com meu núcleo de IA. Por favor, tente novamente mais tarde.";
  }
}

